class Solution:
    def search(self, nums: list[int], target: int) -> int:
        if not nums:
            return -1

        low = 0
        high = len(nums) - 1

        while low <= high:
            mid = (low + high) // 2

            if nums[mid] == target:
                return mid

            # Sol taraf sıralı mı? (nums[low] <= nums[mid] kontrolüyle anlarız)
            if nums[low] <= nums[mid]:
                # Hedef sol sıralı kısımda mı?
                if nums[low] <= target < nums[mid]:
                    high = mid - 1
                else:  # Hedef sağ tarafta olmalı (sağ taraf sıralı olmayabilir)
                    low = mid + 1
            # Sağ taraf sıralı (sol taraf sıralı değilse bu kısma gireriz, yani nums[low] > nums[mid])
            else:
                # Hedef sağ sıralı kısımda mı?
                if nums[mid] < target <= nums[high]:
                    low = mid + 1
                else:  # Hedef sol tarafta olmalı (sol taraf sıralı olmayabilir)
                    high = mid - 1

        return -1
